// Aggregate weekly deltas per competitor × platform
const rows = $input.first().json;
if (!Array.isArray(rows) || !rows.length) {
  throw new Error('No metrics found in last 14 days. Run collectors first.');
}

const now = new Date();
const today = new Date(now.toISOString().split('T')[0]);
const sevenDaysAgo = new Date(today.getTime() - 7*86400000);
const fourteenDaysAgo = new Date(today.getTime() - 14*86400000);

const byKey = {};
for (const r of rows) {
  const brand = r.competitor_handles?.competitors?.name || 'Unknown';
  const platform = r.competitor_handles?.platform || r.platform;
  const handle = r.competitor_handles?.handle || '';
  const k = `${brand}||${platform}||${handle}`;
  if (!byKey[k]) byKey[k] = { brand, platform, handle, points: [] };
  byKey[k].points.push({ date: r.date, followers: r.followers, total_posts: r.total_posts, total_views: r.total_views });
}

const deltas = [];
for (const k of Object.keys(byKey)) {
  const g = byKey[k];
  const thisWeek = g.points.filter(p => new Date(p.date) > sevenDaysAgo);
  const lastWeek = g.points.filter(p => new Date(p.date) > fourteenDaysAgo && new Date(p.date) <= sevenDaysAgo);
  if (!thisWeek.length || !lastWeek.length) continue;
  const latest = thisWeek[thisWeek.length - 1];
  const prior = lastWeek[lastWeek.length - 1];
  deltas.push({
    brand: g.brand,
    platform: g.platform,
    handle: g.handle,
    followers_now: latest.followers,
    followers_delta: (latest.followers || 0) - (prior.followers || 0),
    posts_delta: (latest.total_posts || 0) - (prior.total_posts || 0),
    views_delta: (latest.total_views || 0) - (prior.total_views || 0)
  });
}

return [{ json: { week_ending: today.toISOString().split('T')[0], deltas } }];

const resp = $input.first().json;
const reportMd = resp.content?.[0]?.text || 'No report generated.';
const weekEnding = $('Build Claude Prompt').item.json.week_ending;

return [{ json: {
  subject: `Competitor Intel — Weekly Report (week ending ${weekEnding})`,
  body_markdown: reportMd,
  body_html: reportMd.replace(/\n\n/g, '<br><br>').replace(/\n/g, '<br>').replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
}}];
